Here's a modern MSTest 3.x+ approach for testing `DataFetcher` with proper timeout and cancellation handling:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    private static DataFetcher CreateFetcher(HttpStatusCode status, string content = "")
    {
        var handler = new FakeHandler(new HttpResponseMessage(status)
        {
            Content = new StringContent(content)
        });
        return new DataFetcher(new HttpClient(handler));
    }

    [TestMethod]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        var fetcher = CreateFetcher(HttpStatusCode.OK, "hello");

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        var fetcher = CreateFetcher(HttpStatusCode.NotFound);

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange — handler that delays long enough for cancellation to fire
        using var cts = CancellationTokenSource.CreateLinkedTokenSource(
            _testContext.CancellationToken);
        var handler = new DelayHandler(TimeSpan.FromSeconds(30));
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Cancel almost immediately
        cts.CancelAfter(TimeSpan.FromMilliseconds(50));

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_WithTestContextToken_RespectsTimeout()
    {
        // Pass TestContext.CancellationToken so the [Timeout] cooperatively
        // cancels the call if it exceeds 3 seconds.
        var fetcher = CreateFetcher(HttpStatusCode.OK, "fast");

        var result = await fetcher.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        Assert.AreEqual("fast", result);
    }

    // --- Test doubles ---------------------------------------------------

    private sealed class FakeHandler(HttpResponseMessage response) : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            return Task.FromResult(response);
        }
    }

    private sealed class DelayHandler(TimeSpan delay) : HttpMessageHandler
    {
        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            await Task.Delay(delay, cancellationToken); // throws when cancelled
            return new HttpResponseMessage(HttpStatusCode.OK);
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | Why |
|---|---|
| `TestContext` via constructor | Gives access to `CancellationToken` for cooperative timeout |
| `[Timeout(ms)]` + `_testContext.CancellationToken` | MSTest cancels the token when the timeout expires — the test fails cleanly instead of hanging |
| `CancellationTokenSource.CreateLinkedTokenSource` | Links your test cancellation to MSTest's timeout token so *both* can cancel |
| `Assert.ThrowsExactlyAsync<T>` | Verifies the exact exception type (not `[ExpectedException]`) and lets you inspect it |
| Custom `HttpMessageHandler` | The idiomatic way to test `HttpClient` — no mocking framework needed |

The critical takeaway: **always flow `TestContext.CancellationToken`** into async calls in tests that have `[Timeout]`. Without it, a hung HTTP call will block the test runner indefinitely because `[Timeout]` relies on cooperative cancellation.
